1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — empty and single items
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
8	  });
9	  it("a single sword yields premium of 115 G (100 base + 10 first + 5 fee)", () => {
10	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", material: "steel", enchantment: 1, cursed: false }])).toBe(115);
11	  });
12	  it("a single amulet yields premium of 71 G (60 base + 6 first + 5 fee)", () => {
13	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }])).toBe(71);
14	  });
15	  it("a single staff yields premium of 93 G (80 base + 8 first + 5 fee)", () => {
16	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff", material: "oak", enchantment: 1, cursed: false }])).toBe(93);
17	  });
18	  it.todo("a single potion yields premium of 49 G (40 base + 4 first + 5 fee)");
19	
20	  // Components
21	  it.todo("a single rune (component) yields premium of 33 G (25 base + 2.5 first + 5 fee → rounded up)");
22	  it.todo("2 runes yield premium of 60 G (50 base + 5 first + 5 fee)");
23	  it.todo("3 runes (block) yield premium of 71 G (60 base + 6 first + 5 fee)");
24	  it.todo("4 runes yield premium of 115 G (100 base + 10 first + 5 fee)");
25	  it.todo("3 runes + 3 moonstones (two blocks) yield premium of 137 G (120 base + 12 first + 5 fee)");
26	  it.todo("2 runes + 1 moonstone yields premium of 88 G (75 base + 7.5 first + 5 fee → rounded up)");
27	
28	  // Premium modifiers (single item, newcomer)
29	  it.todo("cursed sword (newcomer, enchantment 3) yields premium of 165 G");
30	  it.todo("highly enchanted sword (enchantment 5, not cursed, newcomer) yields premium of 148 G (100 + 30 high + 10 first + 5 fee = 145; wait recompute)");
31	  it.todo("sword with enchantment 4 (newcomer, not cursed) yields premium of 115 G (no high-enchantment surcharge)");
32	
33	  // Loyalty discount & follow-up contract
34	  it.todo("long-standing customer (2+ years) with a single sword yields premium of 95 G (100 + 10 first − 20 loyalty + 5 fee)");
35	  it.todo("second contract of a long-standing customer adds the 15% follow-up discount");
36	
37	  // Multi-item policies and modifier scope
38	  it.todo("policy with cursed sword + plain amulet yields premium of 220 G (210 + 16 first + 5 fee ... per integration rules)");
39	
40	  // Quote rounding
41	  it.todo("premium with fractional result is rounded up in MHPCO's favor");
42	
43	  // Claim — basic
44	  it.todo("claim on a sword (steel, enchantment 3) with damage 500 G pays 400 G and remainingCap 1600 G");
45	  it.todo("claim on a rune with damage 200 G pays 100 G (full minus 100 deductible)");
46	
47	  // Claim — special clauses
48	  it.todo("dragon-material sword (enchantment 9) damage 1000 G pays 400 G (50% rule wins then deductible)");
49	  it.todo("dragon-material sword (enchantment 5) damage 800 G pays 700 G (full minus deductible)");
50	  it.todo("steel sword (enchantment 9) damage 1000 G pays 400 G (50% then deductible)");
51	
52	  // Claim — multiple damages
53	  it.todo("claim with two damages (sword + amulet) applies deductible per damage entry");
54	
55	  // Claim — cap and successive claims
56	  it.todo("successive claims exhaust the cap and reduce later payouts");
57	
58	  // CLI / scenario integration
59	  it.todo("scenario with a quote step returns premium in results");
60	  it.todo("scenario with a quote followed by a claim returns premium then payout+remainingCap");
61	  it.todo("unknown item type in quote causes error (rejected)");
62	  it.todo("claim referencing item not in policy is rejected");
63	  it.todo("claim with negative damage amount is rejected");
64	});
