1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type Customer = { yearsWithMHPCO: number };
12	
13	const basePriceFor = (item: Item): number =>
14	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
15	
16	const priceForItem = (item: Item): number => {
17	  const basePrice = basePriceFor(item);
18	  return basePrice + basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
19	};
20	
21	export const quote = (_customer: Customer, items: Item[]): number => {
22	  const itemsTotal = items.reduce((sum, item) => sum + priceForItem(item), 0);
23	  return itemsTotal + PROCESSING_FEE;
24	};
25	
26	export const claim = (..._args: unknown[]): unknown => {
27	  return undefined;
28	};
